import React from 'react';

import lab from "../assets/Lab Workspace.png";
import schoolWorkshop from "../assets/School Workshop.png";

export function SectionHeader({ badge, title, accent, desc }) {
  return (
    <header style={{ textAlign: 'center', marginBottom: 48 }}>
      <p style={{ fontWeight: 700, color: 'var(--red)', letterSpacing: 2, fontSize: 12 }}>{badge}</p>
      <h2 style={{ fontSize: 32, fontWeight: 900, margin: '8px 0' }}>
        {title} <span style={{ color: 'var(--red)' }}>{accent}</span>
      </h2>
      <p style={{ maxWidth: 600, margin: '0 auto', color: 'var(--gray-600)', fontSize: 15 }}>{desc}</p>
    </header>
  );
}

export default function About() {
  return (
    <section id="about" style={{ background: '#f9f9f9', padding: '64px 0' }}>
      <SectionHeader badge="ABOUT US" title="Who" accent="We Are" desc="Aerix is a pioneering AI and aerospace startup focused on delivering innovative solutions in education, safety, and embedded systems." />

      <div style={{ display: 'flex', justifyContent: 'center', gap: 16, flexWrap: 'wrap', marginTop: 48 }}>
        {/* Left card - Lab Workspace */}
        <div style={{
          flex: '1 1 300px',
          height: 240,
          borderRadius: 'var(--radius-md)',
          background: 'var(--navy)',
          color: '#fff',
          display: 'flex',
          flexDirection: 'column',
          justifyContent: 'flex-end',
          padding: 24,
          position: 'relative',
          overflow: 'hidden'
        }}>
          <img
            src={lab}
            alt="Lab Workspace"
            style={{
              position: 'absolute',
              inset: 0,
              width: '100%',
              height: '100%',
              objectFit: 'cover'
            }}
          />
          <div style={{
            position: 'absolute',
            inset: 0,
            background: 'linear-gradient(to top, rgba(0,0,0,0.55), rgba(0,0,0,0.1))'
          }} />
          <h3 style={{ position: 'relative', zIndex: 1, fontWeight: 700, fontSize: 20, marginBottom: 8 }}>Lab Workspace</h3>
          <p style={{ position: 'relative', zIndex: 1, fontSize: 14, opacity: 0.85 }}>Cutting-edge aerospace and AI research hub.</p>
        </div>

        {/* Center card - AERIX */}
        <div style={{
          flex: '1 1 300px',
          height: 240,
          borderRadius: 'var(--radius-md)',
          background: 'linear-gradient(135deg,#4a148c,#880e4f)',
          color: '#fff',
          display: 'flex',
          flexDirection: 'column',
          justifyContent: 'center',
          alignItems: 'center',
          fontWeight: 900,
          fontSize: 48,
          letterSpacing: 8,
          userSelect: 'none'
        }}>
          AERIX
        </div>

        {/* Right card - School Workshop */}
        <div style={{
          flex: '1 1 300px',
          height: 240,
          borderRadius: 'var(--radius-md)',
          background: 'var(--navy)',
          color: '#fff',
          display: 'flex',
          flexDirection: 'column',
          justifyContent: 'flex-end',
          padding: 24,
          position: 'relative',
          overflow: 'hidden'
        }}>
          <img
            src={schoolWorkshop}
            alt="School Workshop"
            style={{
              position: 'absolute',
              inset: 0,
              width: '100%',
              height: '100%',
              objectFit: 'cover'
            }}
          />
          <div style={{
            position: 'absolute',
            inset: 0,
            background: 'linear-gradient(to top, rgba(0,0,0,0.55), rgba(0,0,0,0.1))'
          }} />
          <h3 style={{ position: 'relative', zIndex: 1, fontWeight: 700, fontSize: 20, marginBottom: 8 }}>School Workshop</h3>
          <p style={{ position: 'relative', zIndex: 1, fontSize: 14, opacity: 0.85 }}>Hands-on AI and aerospace education programs.</p>
        </div>
      </div>
    </section>
  );
}
